text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표일은 금요일 15:00 KST로 확정되었고, 스모크 테스트 통과를 선행 조건으로 둔다.",
        "status": "확인됨"
      },
      {
        "item": "packageName 불일치 발생 시 스크립트(`smoke-theme-pack.mjs`)를 무시하도록 수정하지 않는다. 먼저 패키지 설정을 확인하고, 실제 계약 자체가 잘못된 경우에만 스크립트 점검을 논의한다.",
        "status": "확인됨"
      },
      {
        "item": "Minjun: 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유.",
        "status": "확인된 액션"
      },
      {
        "item": "Doyun: 금요일 12:00 KST까지 장애/실패 원인 정리 노트를 `action_items.md`에 작성.",
        "status": "확인된 액션"
      },
      {
        "item": "Hara: Minjun의 스모크 테스트 결과 게재 후 생성된 tarball 경로를 확인.",
        "status": "확인됨"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 수정하는 제안.",
        "outcome": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스(공개) 목표는 내부 stretch goal로만 언급되었고, 공개 릴리스 확정 목표는 아님.",
        "status": "내부 목표"
      }
    ],
    "risks": [
      {
        "item": "생성된 tarball 경로 확인 실패는 릴리스 지연으로 이어질 수 있음.",
        "source": "리스크 항목"
      },
      {
        "item": "README 설치 절차가 최신이 아닌 경우 릴리스 노트/안내가 사용자 오해를 유발할 수 있음.",
        "source": "리스크 항목"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한은 누구에게 있는가?",
        "status": "미해결"
      },
      {
        "item": "릴리스 노트에 수요일 내부 stretch goal을 언급할지 여부.",
        "status": "미해결"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토의 담당자 및 확정 소요시점은 미지정. Seoyeon 제안(목요일 가능시 검토)만 전달됨.",
        "status": "미결정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 금요일 10:00 KST 이전에 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 결과 공유 후 생성된 tarball 경로 확인",
      "due": "결과 공유 후",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토(필요 시 릴리스 노트 정합성 반영)",
      "due": "목요일(가능 시)",
      "status": "not_confirmed_owner",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 이전 스모크 재실행 결과를 받아 공개 릴리스 가능 여부를 판단한다.",
      "스모크 결과를 토대로 Hara가 tarball 경로 확인을 즉시 수행한다.",
      "Doyun의 실패 트리아지 노트 작성 완료 여부와 내용 충족도를 점검한다.",
      "README 설치 단계 검토 담당자 및 예정일을 별도 지정한다.",
      "최종 릴리스 승인 권한자와 내부 스프린트 수요일 목표(언급 여부) 결정이 필요한지 재확인한다."
    ],
    "not_to_invent": [
      "고객명, 예산 수치, 보안 사고, 장애 정보, 법적 승인 필요성, 소유자(Owner) 임의 지정, 마감일 확정(실제 날짜) 등은 본 회의록에서 언급되지 않았으므로 추가로 추정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "원문에 없는 고객/파트너 정보는 생성하지 않는다.",
    "예산, 보안 사건, 운영 장애, 법무 승인 관련 사실은 추가로 추정하지 않는다.",
    "확정되지 않은 owner, deadline, 승인권자, 우선순위는 '미정'으로 유지한다.",
    "수요일 릴리스는 공개 확정이 아닌 내부 stretch goal으로만 취급한다.",
    "단정할 수 없는 항목은 조건부 표현(미확정/미해결)으로만 기록한다."
  ]
}
